import{R as s,e as i,f as a,U as t}from"./chunks/framework.DV0oQ0OM.js";const g=JSON.parse('{"title":"Testing and debugging","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/testing-and-debugging.md","filePath":"getting-started/testing-and-debugging.md","lastUpdated":1779440037000}'),n={name:"getting-started/testing-and-debugging.md"};function o(r,e,l,p,h,d){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="testing-and-debugging" tabindex="-1">Testing and debugging <a class="header-anchor" href="#testing-and-debugging" aria-label="Permalink to &quot;Testing and debugging&quot;">​</a></h1><p>When a first React integration is not working, the problem is usually in the connection points between PHP, Craft, and the browser build, not in the component library itself.</p><p>Start with the simple checks below before digging into deeper package APIs.</p><h2 id="first-checks" tabindex="-1">First checks <a class="header-anchor" href="#first-checks" aria-label="Permalink to &quot;First checks&quot;">​</a></h2><ul><li>Does your Craft page actually register the asset bundle?</li><li>Does the page output the mount element your React entry is looking for?</li><li>Did your Vite build produce the same filenames your asset bundle registers?</li><li>Did you import <code>@verbb/plugin-kit-react/style.css</code>, or inject it into the shadow root if you are using Shadow DOM?</li><li>Are you loading the page inside the Craft control panel, where <code>window.Craft</code> exists?</li></ul><h2 id="if-the-page-is-blank" tabindex="-1">If the page is blank <a class="header-anchor" href="#if-the-page-is-blank" aria-label="Permalink to &quot;If the page is blank&quot;">​</a></h2><p>If nothing renders at all, check these first:</p><ol><li>Open the browser console and look for a JavaScript error.</li><li>Confirm your asset bundle is loading the built <code>js</code> file on that page.</li><li>Confirm your selector matches the mount element exactly.</li><li>Confirm your React entry guards against a missing element.</li></ol><p>This is the minimum safe pattern:</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> container</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> document.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getElementById</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;my-plugin-root&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (container) {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  createRoot</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(container).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">render</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">App</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>If the selector is wrong, React will never mount.</p><h2 id="if-the-page-renders-but-looks-unstyled" tabindex="-1">If the page renders but looks unstyled <a class="header-anchor" href="#if-the-page-renders-but-looks-unstyled" aria-label="Permalink to &quot;If the page renders but looks unstyled&quot;">​</a></h2><p>This usually means the CSS did not load where the app is rendering.</p><p>Check which setup you are using:</p><ul><li><strong>Light DOM:</strong> make sure your entry imports <code>@verbb/plugin-kit-react/style.css</code></li><li><strong>Shadow DOM:</strong> make sure you injected the CSS into the shadow root, not just the page</li></ul><p>If the app is in a shadow root, importing the stylesheet globally is not enough on its own.</p><h2 id="if-craft-specific-features-fail" tabindex="-1">If Craft-specific features fail <a class="header-anchor" href="#if-craft-specific-features-fail" aria-label="Permalink to &quot;If Craft-specific features fail&quot;">​</a></h2><p>Functions like <code>createCraftHostBridge()</code> depend on the Craft control panel environment.</p><p>If you see errors around <code>window.Craft</code> or host requests:</p><ul><li>make sure the page is actually running in the CP</li><li>make sure Craft&#39;s CP assets are loaded first</li><li>avoid calling Craft-specific helpers in isolated visual tests unless you provide your own mock bridge</li></ul><p>If you need the deeper details, see <a href="./../api/react-app-apis">React App APIs</a>.</p><h2 id="if-dialogs-menus-or-popovers-appear-in-the-wrong-place" tabindex="-1">If dialogs, menus, or popovers appear in the wrong place <a class="header-anchor" href="#if-dialogs-menus-or-popovers-appear-in-the-wrong-place" aria-label="Permalink to &quot;If dialogs, menus, or popovers appear in the wrong place&quot;">​</a></h2><p>This is usually a portal problem.</p><p>It shows up more often when:</p><ul><li>your app is mounted in Shadow DOM</li><li>a dialog appears behind the Craft header</li><li>a popover renders outside the visible app area</li></ul><p>In that case, check your <code>configurePluginKitReact()</code> setup and make sure the portal target matches the same DOM tree your app is rendered into. For broader Shadow DOM styling issues, see <a href="./css-setup">CSS setup</a>.</p><h2 id="if-form-schema-components-are-missing" tabindex="-1">If form schema components are missing <a class="header-anchor" href="#if-form-schema-components-are-missing" aria-label="Permalink to &quot;If form schema components are missing&quot;">​</a></h2><p>The schema form system expects its field and component types to be registered before rendering.</p><p>If you see warnings such as <code>Unknown form field type</code> or <code>Unknown form component</code>, make sure your calls to <code>registerFormComponents()</code> and <code>registerFormFields()</code> happen before the form engine renders.</p><h2 id="package-development-tools" tabindex="-1">Package development tools <a class="header-anchor" href="#package-development-tools" aria-label="Permalink to &quot;Package development tools&quot;">​</a></h2><p>If you are contributing to <code>plugin-kit-react</code> itself rather than consuming it in your own plugin:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> visual-tests:dev</span></span></code></pre></div><ul><li><code>npm run test</code> is useful for package-level utilities and hooks</li><li><code>npm run visual-tests:dev</code> is useful for checking component states visually in the bespoke visual-tests app</li></ul><p>Most package consumers will do their real testing inside their own plugin project instead.</p>`,34)])])}const u=s(n,[["render",o]]);export{g as __pageData,u as default};
